import{_ as a,c as t,o,ag as i}from"./chunks/framework.Dj4VfQLU.js";const p=JSON.parse('{"title":"Core Features","description":"","frontmatter":{"icon":"list-radio"},"headers":[],"relativePath":"core-features.md","filePath":"core-features.md"}'),r={name:"core-features.md"};function n(s,e,l,d,c,m){return o(),t("div",null,e[0]||(e[0]=[i('<h1 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h1><p>BetterTaxi offers a comprehensive, white-label suite of features designed to support full-scale ride-hailing and parcel delivery operations across a range of user types and business models. Below is a summary of its core functionality:</p><h4 id="👥-multi-role-ecosystem" tabindex="-1">👥 Multi-Role Ecosystem <a class="header-anchor" href="#👥-multi-role-ecosystem" aria-label="Permalink to &quot;👥 Multi-Role Ecosystem&quot;">​</a></h4><p>BetterTaxi is built around three distinct user roles, each with its own dedicated interface:</p><ul><li><strong>Admin Panel</strong>: Full control over operations, users, pricing, zones, and configurations.</li><li><strong>Driver App</strong>: Optimized for on-the-go use, with real-time job offers and navigation.</li><li><strong>Customer App</strong>: Seamless booking experience with tracking, fare estimates, and in-app payments.</li><li><strong>Partner App (Add-on Available)</strong>: Designed for sub-contractors and third-party fleet operators to oversee their driver networks and order management.</li></ul><h4 id="📍-real-time-ride-and-delivery-management" tabindex="-1">📍 Real-Time Ride and Delivery Management <a class="header-anchor" href="#📍-real-time-ride-and-delivery-management" aria-label="Permalink to &quot;📍 Real-Time Ride and Delivery Management&quot;">​</a></h4><ul><li><strong>Live Tracking</strong>: Real-time WebSocket-based tracking for both drivers and customers.</li><li><strong>ETA &amp; Fare Estimates</strong>: Automatically calculated before booking confirmation.</li><li><strong>Dispatch Model</strong>: Uses a <strong>broadcast model</strong> to notify available drivers (with sequential dispatch planned for future updates).</li><li><strong>Geofencing</strong>: Enables zone-based configurations and availability management.</li><li><strong>Route Optimization</strong>: Helps drivers choose the most efficient path based on traffic and distance.</li></ul><h4 id="💳-flexible-payments-promotions" tabindex="-1">💳 Flexible Payments &amp; Promotions <a class="header-anchor" href="#💳-flexible-payments-promotions" aria-label="Permalink to &quot;💳 Flexible Payments &amp; Promotions&quot;">​</a></h4><ul><li>Supports <strong>Cash, Card</strong>, and <strong>Wallet</strong> payment options.</li><li><strong>Promo Codes</strong>: Admin-defined discounts can be applied at checkout.</li><li><strong>Gift Cards</strong>: Customers can send or redeem gift credits for rides and deliveries.</li></ul><h4 id="💬-communication-notifications" tabindex="-1">💬 Communication &amp; Notifications <a class="header-anchor" href="#💬-communication-notifications" aria-label="Permalink to &quot;💬 Communication &amp; Notifications&quot;">​</a></h4><ul><li><strong>In-App Chat</strong>: Enables direct communication between drivers and customers.</li><li><strong>Push Notifications</strong>: Timely alerts for trip status, payments, and updates.</li><li><strong>SMS Support</strong>: For OTP (email notifications coming soon).</li></ul><h4 id="⚙️-admin-control-customization" tabindex="-1">⚙️ Admin Control &amp; Customization <a class="header-anchor" href="#⚙️-admin-control-customization" aria-label="Permalink to &quot;⚙️ Admin Control &amp; Customization&quot;">​</a></h4><ul><li>No-code customization of: <ul><li><strong>Branding</strong> (logos, color themes, app names)</li><li><strong>Fare Structures</strong> and zone-based pricing</li><li><strong>Service Areas</strong> with geofence controls</li></ul></li><li><strong>Zone Price Override</strong>: Set special pricing for specific areas or times.</li><li><strong>Ratings &amp; Cancellation Reasons</strong>: Track performance and understand trip cancellations.</li></ul><h4 id="📈-data-reporting-in-progress" tabindex="-1">📈 Data &amp; Reporting (In Progress) <a class="header-anchor" href="#📈-data-reporting-in-progress" aria-label="Permalink to &quot;📈 Data &amp; Reporting (In Progress)&quot;">​</a></h4><ul><li>Exportable reports and dashboard analytics (coming soon).</li><li>Current tools include transaction summaries, trip logs, and basic user analytics.</li></ul>',15)]))}const g=a(r,[["render",n]]);export{p as __pageData,g as default};
